#include <bits/stdc++.h>
using namespace std;int L,C;vector<char>ch;string o;
bool vow(char c){return c=='a'||c=='e'||c=='i'||c=='o'||c=='u';}
void bt(int start,string cur){if((int)cur.size()==L){int v=0,co=0;for(char c:cur)vow(c)?v++:co++;if(v>=1&&co>=2)o+=cur+"\n";return;}for(int i=start;i<C;i++)bt(i+1,cur+ch[i]);}
int main(){cin>>L>>C;ch.resize(C);for(auto&c:ch)cin>>c;sort(ch.begin(),ch.end());bt(0,"");cout<<o;}
